const text = $json.text || '';
const response_url = $json.response_url;
const user_id = $json.user_id;
const user_name = $json.user_name;

const sample = text.slice(0, 500);
const total = sample.length || 1;

const counts = {
  he: (sample.match(/[\u0590-\u05FF]/g) || []).length,
  ar: (sample.match(/[\u0600-\u06FF]/g) || []).length,
  ru: (sample.match(/[\u0400-\u04FF]/g) || []).length,
  ja: (sample.match(/[\u3040-\u30FF\u4E00-\u9FAF]/g) || []).length,
  zh: (sample.match(/[\u4E00-\u9FAF]/g) || []).length,
  ko: (sample.match(/[\uAC00-\uD7AF]/g) || []).length,
};

const langNames = {
  he: 'Hebrew', ar: 'Arabic', ru: 'Russian',
  ja: 'Japanese', zh: 'Chinese', ko: 'Korean', en: 'English'
};

let detected = 'en', maxCount = 0;
for (const [lang, count] of Object.entries(counts)) {
  if (count > maxCount && count / total > 0.05) { maxCount = count; detected = lang; }
}
if (detected === 'zh' && counts.ja > counts.zh * 0.3) detected = 'ja';

// Store full text in staticData.
// Slack button values are capped at 2000 chars — long texts get silently truncated.
// A short session key in the button value is resolved back to the full text on click.
const staticData = $getWorkflowStaticData('global');
if (!staticData.textSessions) staticData.textSessions = {};

// Expire sessions older than 1 hour
const oneHourAgo = Date.now() - 3600000;
for (const k of Object.keys(staticData.textSessions)) {
  if (staticData.textSessions[k].ts < oneHourAgo) delete staticData.textSessions[k];
}

const sessionKey = 's' + Date.now().toString(36) + Math.random().toString(36).slice(2, 6);
staticData.textSessions[sessionKey] = { text, ts: Date.now() };

return {
  json: {
    session_key: sessionKey,
    detected_language: detected,
    detected_language_name: langNames[detected] || 'English',
    text_preview: text.length > 150 ? text.slice(0, 150) + '…' : text,
    response_url,
    user_id,
    user_name
  }
};

