const body = $input.first().json.body;
const payload = JSON.parse(body.payload);

const staticData = $getWorkflowStaticData('global');
if (!staticData.textSessions) staticData.textSessions = {};

// Expire sessions older than 1 hour
const oneHourAgo = Date.now() - 3600000;
for (const k of Object.keys(staticData.textSessions)) {
  if (staticData.textSessions[k].ts < oneHourAgo) delete staticData.textSessions[k];
}

// Case 1: Message shortcut ("Translate this" right-click menu)
if (payload.type === 'message_action') {
  const text = payload.message.text || '';
  const sessionKey = 's' + Date.now().toString(36) + Math.random().toString(36).slice(2, 6);
  staticData.textSessions[sessionKey] = { text, ts: Date.now() };
  return {
    json: {
      text,
      session_key: sessionKey,
      target_language: null,
      source_language: 'auto',
      response_url: payload.response_url,
      user_id: payload.user.id,
      user_name: payload.user.name,
      trigger_type: 'shortcut'
    }
  };
}

// Case 2: Language button click
const action = payload.actions[0];
const value = action.value;

// Format: "targetLang|sourceLang|sessionKey"
const firstPipe = value.indexOf('|');
const secondPipe = value.indexOf('|', firstPipe + 1);
const target_language = value.slice(0, firstPipe);
const source_language = value.slice(firstPipe + 1, secondPipe);
const sessionKey = value.slice(secondPipe + 1);

// Resolve session key → full original text
const session = staticData.textSessions[sessionKey];
const text = session ? session.text : '';

if (!text) {
  // Session expired — nothing we can do, just stop silently
  console.error('[Translate] Session expired for key:', sessionKey);
  return [];
}

const user_id = payload.user.id;
const action_id = action.action_id;

// Double-click deduplication: ignore same user+action within 10s
if (!staticData.recentActions) staticData.recentActions = {};
const actionKey = `${user_id}_${action_id}_${sessionKey}`;
const now = Date.now();
for (const k of Object.keys(staticData.recentActions)) {
  if (staticData.recentActions[k] < now - 10000) delete staticData.recentActions[k];
}
if (staticData.recentActions[actionKey]) return []; // duplicate click
staticData.recentActions[actionKey] = now;

return {
  json: {
    target_language,
    source_language,
    text,
    session_key: sessionKey,
    response_url: payload.response_url,
    user_id,
    user_name: payload.user.name,
    trigger_type: 'button'
  }
};

