  const keyMatch = str.match(/"translation"\s*:\s*"/);
  if (!keyMatch) throw new Error("No translation field found");
  const tail = str.slice(keyMatch.index + keyMatch[0].length);
  const lastBrace = tail.lastIndexOf("}");
  if (lastBrace === -1) throw new Error("No closing brace");
  let closingQuote = -1;
  for (let i = lastBrace - 1; i >= 0; i--) {
    const ch = tail[i];
    if (ch === '"') { closingQuote = i; break; }
    if (!/\s/.test(ch) && ch !== ",") break;
  }
  if (closingQuote === -1) throw new Error("No closing quote");
  let value = tail.slice(0, closingQuote);
  return value
    .replace(/\\n/g, "\n").replace(/\\r/g, "\r").replace(/\\t/g, "\t")
    .replace(/\\"/g, '"').replace(/\\\\/g, "\\")
    .replace(/\\u([0-9a-fA-F]{4})/g, (_, h) => String.fromCharCode(parseInt(h, 16)));
}

let translation = "";
let parseError = null;
try {
  translation = extractTranslation(response);
  if (!translation) throw new Error("Model returned empty translation");
  if (rtlLangs.includes(targetLang)) translation = `\u202B${translation}\u202C`;
} catch (err) {
  parseError = err.message;
}

const MAX = 2900;
const trim = s => s.length > MAX ? s.slice(0, MAX) + "… [truncated]" : s;

const blocks = parseError ? [
  { type: "header", text: { type: "plain_text", text: "❌ Translation Failed" } },
  { type: "section", text: { type: "mrkdwn", text: `*Reason:* ${parseError}\n\n*Original:*\n\`\`\`${trim(originalText)}\`\`\`` } }
] : [
  { type: "header", text: { type: "plain_text", text: "🌐 Translation Complete" } },
  { type: "section", text: { type: "mrkdwn", text: `*📝 Original (${sourceFlag} ${sourceName}):*\n\`\`\`${trim(originalText)}\`\`\`` } },
  { type: "section", text: { type: "mrkdwn", text: `*${targetFlag} ${targetName} Translation:*\n\`\`\`${trim(translation)}\`\`\`` } }
];

return { json: { response_url: inputData.response_url, slack_payload: { replace_original: true, blocks } } };
